  1246 |       return IfFold([&]() { return Builder.CreateZExt(LogX, Op->getType()); });
  1247 | 
  1248 |   // log2(X << Y) -> log2(X) + Y
  1249 |   // FIXME: Require one use unless X is 1?
  1250 |   if (match(Op, m_Shl(m_Value(X), m_Value(Y)))) {
  1251 |     auto *BO = cast<OverflowingBinaryOperator>(Op);
