  1253 |     if (AssumeNonZero || BO->hasNoUnsignedWrap() || BO->hasNoSignedWrap())
  1254 |       if (Value *LogX = takeLog2(Builder, X, Depth, AssumeNonZero, DoFold))
  1255 |         return IfFold([&]() { return Builder.CreateAdd(LogX, Y); });
  1256 |   }
  1257 | 
  1258 |   // log2(Cond ? X : Y) -> Cond ? log2(X) : log2(Y)
  1259 |   // FIXME: missed optimization: if one of the hands of select is/contains
  1260 |   //        undef, just directly pick the other one.
  1261 |   // FIXME: can both hands contain undef?
  1262 |   // FIXME: Require one use?
  1263 |   if (SelectInst *SI = dyn_cast<SelectInst>(Op))
