  1272 |   // log2(umin(X, Y)) -> umin(log2(X), log2(Y))
  1273 |   // log2(umax(X, Y)) -> umax(log2(X), log2(Y))
  1274 |   auto *MinMax = dyn_cast<MinMaxIntrinsic>(Op);
