  1312 |     Constant *TruncC = IC.getLosslessUnsignedTrunc(C, X->getType());
  1313 |     if (!TruncC)
  1314 |       return nullptr;
  1315 | 
  1316 |     // udiv (zext X), C --> zext (udiv X, C')
  1317 |     // urem (zext X), C --> zext (urem X, C')
  1318 |     return new ZExtInst(IC.Builder.CreateBinOp(Opcode, X, TruncC), Ty);
  1319 |   }
  1320 |   if (isa<Instruction>(D) && match(D, m_OneUse(m_ZExt(m_Value(X)))) &&
  1321 |       match(N, m_Constant(C))) {
  1322 |     // If the constant is the same in the smaller type, use the narrow version.
  1323 |     Constant *TruncC = IC.getLosslessUnsignedTrunc(C, X->getType());
  1324 |     if (!TruncC)
  1325 |       return nullptr;
  1326 | 
  1327 |     // udiv C, (zext X) --> zext (udiv C', X)
  1328 |     // urem C, (zext X) --> zext (urem C', X)
  1329 |     return new ZExtInst(IC.Builder.CreateBinOp(Opcode, TruncC, X), Ty);
